// HasTicket applies the HasEdge predicate on the "ticket" edge.
func HasTicket() predicate.FeishuTicketSync {
	return predicate.FeishuTicketSync(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, TicketTable, TicketColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasTicketWith applies the HasEdge predicate on the "ticket" edge with a given conditions (other predicates).
func HasTicketWith(preds ...predicate.Ticket) predicate.FeishuTicketSync {
	return predicate.FeishuTicketSync(func(s *sql.Selector) {
		step := newTicketStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.FeishuTicketSync) predicate.FeishuTicketSync {
	return predicate.FeishuTicketSync(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.FeishuTicketSync) predicate.FeishuTicketSync {
	return predicate.FeishuTicketSync(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.FeishuTicketSync) predicate.FeishuTicketSync {
	return predicate.FeishuTicketSync(sql.NotPredicates(p))
}
